import { useState } from "react";
import { addVehicle } from "../../api/vehicleApi";

function AddVehicle() {
  const [vehicle, setVehicle] = useState({
    model: "",
    brand: "",
    year: "",
    price: "",
    status: "available",
  });

  const vehicleTypes = ["SUV", "Sedan", "Hatchback", "Truck", "Van", "Coupe"];


  const handleChange = (e) => {
    setVehicle({ ...vehicle, [e.target.name]: e.target.value });
  };

  const submit = async (e) => {
    e.preventDefault();
    try {
      await addVehicle(vehicle);
      alert("Vehicle added successfully");
      setVehicle({
        model: "",
        brand: "",
        year: "",
        price: "",
        status: "available",
      });
    } catch (err) {
      alert(err.response?.data?.message || "Error adding vehicle");
    }
  };

  return (
    <form onSubmit={submit}>
      <h2>Add Vehicle</h2>

      <input name="brand" placeholder="Brand" value={vehicle.brand} onChange={handleChange} />
      <input name="model" placeholder="Model" value={vehicle.model} onChange={handleChange} />
      <input name="year" type="number" placeholder="Year" value={vehicle.year} onChange={handleChange} />
      <input name="price" type="number" placeholder="Price" value={vehicle.price} onChange={handleChange} />

      <select name="status" value={vehicle.status} onChange={handleChange}>
        <option value="available">Available</option>
        <option value="reserved">Reserved</option>
        <option value="sold">Sold</option>
      </select>

      <button type="submit">Save</button>
    </form>
  );
}

export default AddVehicle;
